/* ═══���═══════════════════════════════════════════════════════════════════════
   AURA ALPHA — Cash Ledger Component
   Per-user verified deposits, withdrawals, running balance.
   Design: dark theme, JetBrains Mono amounts, green deposits, red withdrawals.
   ═══════════════════════════════════��═══════════════════════════════════════ */
import { useState, useEffect, useCallback, useMemo } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { api } from '../utils/api';

// ── Design tokens ─────────────────────────────────────────────────────────
const C = {
  bg: '#0D1117',
  surface: '#161B22',
  surface2: '#1C2128',
  border: '#30363D',
  text: '#E6EDF3',
  textSec: '#8B949E',
  green: '#3FB950',
  red: '#F85149',
  blue: '#58A6FF',
  amber: '#D29922',
  purple: '#BC8CFF',
};

const mono = "'JetBrains Mono', 'Fira Code', monospace";
const body = "'Plus Jakarta Sans', -apple-system, sans-serif";

// ── Formatters ���───────────────────────────────────────────────────────────
function fmt$(val) {
  if (val == null || isNaN(val)) return '--';
  return new Intl.NumberFormat('en-US', {
    style: 'currency', currency: 'USD',
    minimumFractionDigits: 2, maximumFractionDigits: 2,
  }).format(val);
}

function fmtDate(dateStr) {
  if (!dateStr) return '--';
  try {
    const d = new Date(dateStr + (dateStr.includes('Z') || dateStr.includes('+') ? '' : 'Z'));
    return d.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
  } catch {
    return dateStr;
  }
}

function fmtDateTime(dateStr) {
  if (!dateStr) return '--';
  try {
    const d = new Date(dateStr + (dateStr.includes('Z') || dateStr.includes('+') ? '' : 'Z'));
    return d.toLocaleString('en-US', {
      month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit',
    });
  } catch {
    return dateStr;
  }
}

// ── Shared styles ��────────────────────────────────────────────────────────
const card = {
  background: C.surface,
  border: `1px solid ${C.border}`,
  borderRadius: 10,
  padding: '16px 20px',
};

const fadeUp = {
  initial: { opacity: 0, y: 12 },
  animate: { opacity: 1, y: 0, transition: { duration: 0.25, ease: [0.4, 0, 0.2, 1] } },
};

// ── Monthly Bar Chart (pure SVG) ──────────────────────────────────────────
function MonthlyChart({ data }) {
  if (!data || data.length === 0) {
    return (
      <div style={{
        height: 120, display: 'flex', alignItems: 'center', justifyContent: 'center',
        color: C.textSec, fontSize: 12, fontFamily: body,
      }}>
        No monthly data yet
      </div>
    );
  }

  const reversed = [...data].reverse(); // oldest first for chart
  const width = 600;
  const height = 120;
  const pad = { top: 10, bottom: 24, left: 10, right: 10 };
  const chartW = width - pad.left - pad.right;
  const chartH = height - pad.top - pad.bottom;
  const barGroupW = Math.min(60, chartW / reversed.length);
  const barW = (barGroupW - 4) / 2;
  const maxVal = Math.max(...reversed.map(d => Math.max(d.deposited, d.withdrawn)), 1);
  const scaleY = chartH / maxVal;

  return (
    <svg viewBox={`0 0 ${width} ${height}`} style={{ width: '100%', height }}>
      {reversed.map((d, i) => {
        const x = pad.left + i * (chartW / reversed.length) + (chartW / reversed.length - barGroupW) / 2;
        const depH = d.deposited * scaleY;
        const wdH = d.withdrawn * scaleY;
        return (
          <g key={d.month}>
            {/* Deposit bar */}
            <rect
              x={x} y={pad.top + chartH - depH}
              width={barW} height={Math.max(depH, 1)}
              rx={2} fill={C.green} opacity={0.8}
            />
            {/* Withdrawal bar */}
            <rect
              x={x + barW + 2} y={pad.top + chartH - wdH}
              width={barW} height={Math.max(wdH, 1)}
              rx={2} fill={C.red} opacity={0.8}
            />
            {/* Month label */}
            <text
              x={x + barGroupW / 2} y={height - 4}
              fill={C.textSec} fontSize="8" fontFamily={mono}
              textAnchor="middle"
            >
              {d.month?.slice(5) || ''}
            </text>
          </g>
        );
      })}
      {/* Legend */}
      <circle cx={width - 90} cy={8} r={3} fill={C.green} />
      <text x={width - 84} y={11} fill={C.textSec} fontSize="8" fontFamily={body}>Deposits</text>
      <circle cx={width - 42} cy={8} r={3} fill={C.red} />
      <text x={width - 36} y={11} fill={C.textSec} fontSize="8" fontFamily={body}>Withdrawals</text>
    </svg>
  );
}

// ── Summary Card ───���──────────────────────────────────────────────────────
function SummaryCard({ label, value, color, icon }) {
  return (
    <motion.div {...fadeUp} style={{
      ...card,
      flex: '1 1 0',
      minWidth: 140,
      display: 'flex',
      flexDirection: 'column',
      gap: 6,
    }}>
      <div style={{
        display: 'flex', alignItems: 'center', gap: 6,
        color: C.textSec, fontSize: 11, fontFamily: body, fontWeight: 500,
        textTransform: 'uppercase', letterSpacing: '0.5px',
      }}>
        {icon}
        {label}
      </div>
      <div style={{
        fontFamily: mono, fontSize: 20, fontWeight: 600, color,
      }}>
        {fmt$(value)}
      </div>
    </motion.div>
  );
}

// ── Type badge ────────────────────────────────────────────────────────────
function TypeBadge({ type }) {
  const isDeposit = type === 'deposit';
  const color = isDeposit ? C.green : C.red;
  return (
    <span style={{
      display: 'inline-flex', alignItems: 'center', gap: 4,
      padding: '2px 8px', borderRadius: 4,
      background: `${color}18`, color,
      fontSize: 11, fontFamily: body, fontWeight: 600,
      textTransform: 'uppercase', letterSpacing: '0.3px',
    }}>
      {isDeposit ? '\u2191' : '\u2193'} {type}
    </span>
  );
}

// ── Main Component ──────────────��─────────────────────────────────────────
export default function CashLedger({ botName }) {
  const [ledger, setLedger] = useState(null);
  const [summary, setSummary] = useState(null);
  const [monthly, setMonthly] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [sortField, setSortField] = useState('date');
  const [sortAsc, setSortAsc] = useState(false);

  const fetchData = useCallback(async () => {
    try {
      const botParam = botName ? `?bot=${encodeURIComponent(botName)}` : '';
      const [ledgerRes, summaryRes, monthlyRes] = await Promise.all([
        api(`/ledger/${botParam}`),
        api('/ledger/summary'),
        api('/ledger/monthly'),
      ]);
      if (ledgerRes) setLedger(ledgerRes);
      if (summaryRes) setSummary(summaryRes);
      if (monthlyRes) setMonthly(monthlyRes);
      setError(null);
    } catch (err) {
      setError(err?.message || 'Failed to load ledger');
    } finally {
      setLoading(false);
    }
  }, [botName]);

  useEffect(() => {
    fetchData();
    const interval = setInterval(fetchData, 30000);
    return () => clearInterval(interval);
  }, [fetchData]);

  // Sort entries
  const sortedEntries = useMemo(() => {
    if (!ledger?.entries) return [];
    const entries = [...ledger.entries];
    entries.sort((a, b) => {
      let va, vb;
      switch (sortField) {
        case 'date': va = a.date; vb = b.date; break;
        case 'type': va = a.type; vb = b.type; break;
        case 'amount': va = Math.abs(a.amount); vb = Math.abs(b.amount); break;
        case 'balance': va = a.balance_after; vb = b.balance_after; break;
        case 'broker': va = a.broker; vb = b.broker; break;
        default: va = a.date; vb = b.date;
      }
      if (va < vb) return sortAsc ? -1 : 1;
      if (va > vb) return sortAsc ? 1 : -1;
      return 0;
    });
    return entries;
  }, [ledger?.entries, sortField, sortAsc]);

  const handleSort = (field) => {
    if (sortField === field) {
      setSortAsc(!sortAsc);
    } else {
      setSortField(field);
      setSortAsc(false);
    }
  };

  const sortArrow = (field) => {
    if (sortField !== field) return '';
    return sortAsc ? ' \u25B2' : ' \u25BC';
  };

  // ── Loading ─────────────────────────────────────────────────────────────
  if (loading) {
    return (
      <div style={{
        display: 'flex', alignItems: 'center', justifyContent: 'center',
        height: 200, color: C.textSec, fontFamily: body, fontSize: 13,
      }}>
        <div style={{
          width: 24, height: 24, border: `2px solid ${C.border}`,
          borderTopColor: C.blue, borderRadius: '50%',
          animation: 'spin 0.8s linear infinite',
          marginRight: 10,
        }} />
        Loading ledger...
        <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
      </div>
    );
  }

  // ── Error ───────────────────────────────────────────────────────────────
  if (error && !ledger) {
    return (
      <div style={{
        display: 'flex', flexDirection: 'column', alignItems: 'center',
        justifyContent: 'center', height: 200, gap: 8,
        color: C.red, fontFamily: body, fontSize: 13,
      }}>
        <span>Failed to load ledger</span>
        <span style={{ color: C.textSec, fontSize: 11 }}>{error}</span>
        <button onClick={fetchData} style={{
          marginTop: 8, padding: '6px 16px', borderRadius: 6,
          border: `1px solid ${C.border}`, background: C.surface,
          color: C.text, fontFamily: body, fontSize: 12, cursor: 'pointer',
        }}>
          Retry
        </button>
      </div>
    );
  }

  const entries = sortedEntries;
  const balance = ledger?.current_balance ?? 0;

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
      {/* ── Running Balance (hero) ────────────────────────────────────── */}
      <motion.div {...fadeUp} style={{
        ...card,
        display: 'flex', flexDirection: 'column', alignItems: 'center',
        gap: 4, padding: '24px 20px',
      }}>
        <div style={{
          color: C.textSec, fontSize: 11, fontFamily: body,
          textTransform: 'uppercase', letterSpacing: '0.5px', fontWeight: 500,
        }}>
          Current Cash Balance
        </div>
        <div style={{
          fontFamily: mono, fontSize: 36, fontWeight: 700,
          color: balance >= 0 ? C.green : C.red,
          lineHeight: 1.1,
        }}>
          {fmt$(balance)}
        </div>
        <div style={{
          color: C.textSec, fontSize: 11, fontFamily: body,
          marginTop: 4,
        }}>
          {entries.length} verified transaction{entries.length !== 1 ? 's' : ''}
        </div>
      </motion.div>

      {/* ── Summary Cards ─────────────────────────────────────────────── */}
      {summary && (
        <div style={{ display: 'flex', gap: 12, flexWrap: 'wrap' }}>
          <SummaryCard
            label="Total Deposited"
            value={summary.total_deposited}
            color={C.green}
            icon={
              <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke={C.green} strokeWidth="2.5">
                <path d="M12 19V5M5 12l7-7 7 7" />
              </svg>
            }
          />
          <SummaryCard
            label="Total Withdrawn"
            value={summary.total_withdrawn}
            color={C.red}
            icon={
              <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke={C.red} strokeWidth="2.5">
                <path d="M12 5v14M5 12l7 7 7-7" />
              </svg>
            }
          />
          <SummaryCard
            label="Net Transfers"
            value={summary.net}
            color={summary.net >= 0 ? C.green : C.red}
            icon={
              <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke={C.blue} strokeWidth="2.5">
                <path d="M12 2v20M2 12h20" />
              </svg>
            }
          />
        </div>
      )}

      {/* ── Monthly Chart ─────────────────────────────────────────────── */}
      {monthly?.monthly && monthly.monthly.length > 0 && (
        <motion.div {...fadeUp} style={{ ...card }}>
          <div style={{
            color: C.textSec, fontSize: 11, fontFamily: body,
            textTransform: 'uppercase', letterSpacing: '0.5px',
            fontWeight: 500, marginBottom: 8,
          }}>
            Monthly Overview
          </div>
          <MonthlyChart data={monthly.monthly} />
        </motion.div>
      )}

      {/* ── Transaction Table ─────────────────────────────────────────── */}
      <motion.div {...fadeUp} style={{
        ...card,
        padding: 0,
        overflow: 'hidden',
      }}>
        <div style={{
          padding: '12px 20px',
          borderBottom: `1px solid ${C.border}`,
          display: 'flex', alignItems: 'center', justifyContent: 'space-between',
        }}>
          <div style={{
            display: 'flex', alignItems: 'center', gap: 8,
            color: C.text, fontSize: 13, fontFamily: body, fontWeight: 600,
          }}>
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke={C.blue} strokeWidth="2">
              <rect x="3" y="3" width="18" height="18" rx="2" ry="2" />
              <path d="M3 9h18M9 21V9" />
            </svg>
            Transaction History
          </div>
          <span style={{
            color: C.textSec, fontSize: 11, fontFamily: mono,
          }}>
            {entries.length} entries
          </span>
        </div>

        <div style={{ overflowX: 'auto' }}>
          <table style={{
            width: '100%', borderCollapse: 'collapse',
            fontFamily: body, fontSize: 12,
          }}>
            <thead>
              <tr>
                {[
                  { key: 'date', label: 'Date' },
                  { key: 'type', label: 'Type' },
                  { key: 'amount', label: 'Amount' },
                  { key: 'balance', label: 'Balance After' },
                  { key: 'broker', label: 'Broker' },
                  { key: null, label: 'Reference' },
                  { key: null, label: 'Status' },
                ].map((col, i) => (
                  <th
                    key={i}
                    onClick={col.key ? () => handleSort(col.key) : undefined}
                    style={{
                      padding: '10px 14px',
                      textAlign: col.key === 'amount' || col.key === 'balance' ? 'right' : 'left',
                      color: C.textSec,
                      fontSize: 10,
                      fontWeight: 600,
                      textTransform: 'uppercase',
                      letterSpacing: '0.5px',
                      borderBottom: `1px solid ${C.border}`,
                      cursor: col.key ? 'pointer' : 'default',
                      userSelect: 'none',
                      whiteSpace: 'nowrap',
                      fontFamily: body,
                    }}
                  >
                    {col.label}{col.key ? sortArrow(col.key) : ''}
                  </th>
                ))}
              </tr>
            </thead>
            <tbody>
              <AnimatePresence>
                {entries.length === 0 ? (
                  <tr>
                    <td colSpan={7} style={{
                      padding: 40, textAlign: 'center',
                      color: C.textSec, fontSize: 13, fontFamily: body,
                    }}>
                      No verified transactions yet
                    </td>
                  </tr>
                ) : (
                  entries.map((entry, idx) => (
                    <motion.tr
                      key={entry.id || idx}
                      initial={{ opacity: 0 }}
                      animate={{ opacity: 1 }}
                      transition={{ delay: idx * 0.02, duration: 0.15 }}
                      style={{
                        borderBottom: `1px solid ${C.border}22`,
                        cursor: 'default',
                      }}
                      onMouseEnter={(e) => {
                        e.currentTarget.style.background = `${C.surface2}`;
                      }}
                      onMouseLeave={(e) => {
                        e.currentTarget.style.background = 'transparent';
                      }}
                    >
                      {/* Date */}
                      <td style={{
                        padding: '10px 14px', color: C.textSec,
                        fontFamily: mono, fontSize: 11, whiteSpace: 'nowrap',
                      }}>
                        {fmtDateTime(entry.date)}
                      </td>

                      {/* Type */}
                      <td style={{ padding: '10px 14px' }}>
                        <TypeBadge type={entry.type} />
                      </td>

                      {/* Amount */}
                      <td style={{
                        padding: '10px 14px', textAlign: 'right',
                        fontFamily: mono, fontSize: 13, fontWeight: 600,
                        color: entry.type === 'deposit' ? C.green : C.red,
                      }}>
                        {entry.type === 'deposit' ? '+' : '-'}{fmt$(entry.abs_amount)}
                      </td>

                      {/* Balance After */}
                      <td style={{
                        padding: '10px 14px', textAlign: 'right',
                        fontFamily: mono, fontSize: 12,
                        color: entry.balance_after >= 0 ? C.text : C.red,
                      }}>
                        {fmt$(entry.balance_after)}
                      </td>

                      {/* Broker */}
                      <td style={{
                        padding: '10px 14px', color: C.textSec,
                        fontSize: 11, fontFamily: body,
                      }}>
                        {entry.broker}
                      </td>

                      {/* Reference */}
                      <td style={{
                        padding: '10px 14px', color: C.textSec,
                        fontFamily: mono, fontSize: 10,
                      }}>
                        {entry.ref_id}
                      </td>

                      {/* Status */}
                      <td style={{ padding: '10px 14px' }}>
                        <span style={{
                          display: 'inline-flex', alignItems: 'center', gap: 4,
                          padding: '2px 8px', borderRadius: 4,
                          background: `${C.green}12`, color: C.green,
                          fontSize: 10, fontFamily: body, fontWeight: 600,
                          textTransform: 'uppercase', letterSpacing: '0.3px',
                        }}>
                          <svg width="8" height="8" viewBox="0 0 24 24" fill="none" stroke={C.green} strokeWidth="3">
                            <polyline points="20 6 9 17 4 12" />
                          </svg>
                          {entry.status}
                        </span>
                      </td>
                    </motion.tr>
                  ))
                )}
              </AnimatePresence>
            </tbody>
          </table>
        </div>

        {/* Footer badge */}
        <div style={{
          padding: '10px 20px',
          borderTop: `1px solid ${C.border}`,
          display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 6,
        }}>
          <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke={C.green} strokeWidth="2.5">
            <path d="M22 11.08V12a10 10 0 1 1-5.93-9.14" />
            <polyline points="22 4 12 14.01 9 11.01" />
          </svg>
          <span style={{
            color: C.green, fontSize: 10, fontFamily: body,
            fontWeight: 600, textTransform: 'uppercase', letterSpacing: '0.5px',
          }}>
            All verified by broker
          </span>
        </div>
      </motion.div>

      {/* ── Per-Bot Breakdown (from summary) ──────────────────────────── */}
      {summary?.by_bot && Object.keys(summary.by_bot).length > 1 && (
        <motion.div {...fadeUp} style={{ ...card }}>
          <div style={{
            color: C.textSec, fontSize: 11, fontFamily: body,
            textTransform: 'uppercase', letterSpacing: '0.5px',
            fontWeight: 500, marginBottom: 12,
          }}>
            By Bot
          </div>
          <div style={{ display: 'flex', gap: 12, flexWrap: 'wrap' }}>
            {Object.entries(summary.by_bot).map(([botKey, data]) => (
              <div key={botKey} style={{
                flex: '1 1 0', minWidth: 140,
                padding: '10px 14px', borderRadius: 8,
                background: C.surface2, border: `1px solid ${C.border}`,
              }}>
                <div style={{
                  color: C.blue, fontSize: 12, fontFamily: body,
                  fontWeight: 600, marginBottom: 6,
                }}>
                  {botKey}
                </div>
                <div style={{ display: 'flex', flexDirection: 'column', gap: 3 }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                    <span style={{ color: C.textSec, fontSize: 10, fontFamily: body }}>Deposited</span>
                    <span style={{ color: C.green, fontSize: 11, fontFamily: mono }}>{fmt$(data.deposited)}</span>
                  </div>
                  <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                    <span style={{ color: C.textSec, fontSize: 10, fontFamily: body }}>Withdrawn</span>
                    <span style={{ color: C.red, fontSize: 11, fontFamily: mono }}>{fmt$(data.withdrawn)}</span>
                  </div>
                  <div style={{
                    display: 'flex', justifyContent: 'space-between',
                    borderTop: `1px solid ${C.border}`, paddingTop: 3, marginTop: 2,
                  }}>
                    <span style={{ color: C.textSec, fontSize: 10, fontFamily: body }}>Net</span>
                    <span style={{
                      color: data.net >= 0 ? C.green : C.red,
                      fontSize: 11, fontFamily: mono, fontWeight: 600,
                    }}>
                      {fmt$(data.net)}
                    </span>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </motion.div>
      )}
    </div>
  );
}
